// Extract search keywords from the RSS headline
const title = $input.first().json.title || '';
// Remove common stop words and short words
const stopWords = new Set(['the', 'a', 'an', 'is', 'are', 'was', 'were', 'will', 'be', 'to', 'of', 'in', 'for', 'on', 'at', 'by', 'and', 'or', 'but', 'not', 'it', 'its', 'has', 'have', 'had', 'that', 'this', 'with', 'from', 'as', 'says', 'said']);
const keywords = title
  .replace(/[^a-zA-Z0-9\s]/g, '')
  .split(/\s+/)
  .filter(w => w.length > 2 && !stopWords.has(w.toLowerCase()))
  .slice(0, 5)
  .join(' ');

return [{
  json: {
    title,
    link: $input.first().json.link || '',
    pubDate: $input.first().json.pubDate || '',
    searchQuery: keywords
  }
}];

// Get the top matching market and extract the first token ID for pricing
const markets = $input.all();
if (markets.length === 0) {
  return [{ json: { _noMatch: true } }];
}

const top = markets[0].json;

// Parse tokens -- Gamma returns these as JSON-encoded strings
let tokens = top.tokens || [];
if (typeof tokens === 'string') {
  try { tokens = JSON.parse(tokens); } catch(e) { tokens = []; }
}

let clobTokenIds = top.clobTokenIds || [];
if (typeof clobTokenIds === 'string') {
  try { clobTokenIds = JSON.parse(clobTokenIds); } catch(e) { clobTokenIds = []; }
}

let outcomes = top.outcomes || [];
if (typeof outcomes === 'string') {
  try { outcomes = JSON.parse(outcomes); } catch(e) { outcomes = []; }
}

let outcomePrices = top.outcomePrices || [];
if (typeof outcomePrices === 'string') {
  try { outcomePrices = JSON.parse(outcomePrices); } catch(e) { outcomePrices = []; }
}

const firstTokenId = (tokens[0] && tokens[0].tokenId) || clobTokenIds[0] || '';

return [{
  json: {
    question: top.question || top.title || 'Unknown',
    conditionId: top.conditionId || '',
    slug: top.slug || '',
    volume: top.volume || 0,
    tokenId: firstTokenId,
    outcomes,
    outcomePrices,
    _noMatch: false
  }
}];

// Combine news + market data + prices into an AI analysis prompt
const price = $input.first().json;

// Pull forward data from earlier nodes via $('nodeName')
const newsData = $('Extract Keywords').first().json;
const marketData = $('Pick Top Market').first().json;

const prompt = `You are a prediction market analyst. Analyze whether this news affects the given Polymarket market.

NEWS HEADLINE: ${newsData.title}
NEWS URL: ${newsData.link}
PUBLISHED: ${newsData.pubDate}

MATCHED MARKET: ${marketData.question}
CURRENT PRICE: $${Number(price.price || price.midpoint || 0).toFixed(3)}
MIDPOINT: $${Number(price.midpoint || 0).toFixed(3)}
SPREAD: ${JSON.stringify(price.spread || 'N/A')}
VOLUME: $${Number(marketData.volume || 0).toLocaleString()}

Respond with JSON only:
{
  "relevant": true/false,
  "confidence": 0-100,
  "direction": "YES_UP" | "YES_DOWN" | "NEUTRAL",
  "reasoning": "1-2 sentence explanation"
}`;

return [{
  json: {
    prompt,
    newsTitle: newsData.title,
    newsLink: newsData.link,
    marketQuestion: marketData.question,
    currentPrice: price.price || price.midpoint || 0,
    slug: marketData.slug
  }
}];

// Parse AI response and determine if confidence exceeds threshold
const aiRaw = $input.first().json;
const promptData = $('Build AI Prompt').first().json;
let text = aiRaw.text || aiRaw.message?.content || JSON.stringify(aiRaw);

// Try to extract JSON from the response
let analysis = { relevant: false, confidence: 0, direction: 'NEUTRAL', reasoning: 'Could not parse AI response' };
try {
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  }
} catch(e) {
  // Keep defaults
}

return [{
  json: {
    confidence: analysis.confidence || 0,
    direction: analysis.direction || 'NEUTRAL',
    reasoning: analysis.reasoning || '',
    relevant: analysis.relevant || false,
    newsTitle: promptData.newsTitle,
    newsLink: promptData.newsLink,
    marketQuestion: promptData.marketQuestion,
    currentPrice: promptData.currentPrice,
    slug: promptData.slug
  }
}];

